        public static randomGenerator(min: any, max: any): any {
            return math.floor(math.random() * (max - min + 1) + min);
        }

        public static getOddsRangeByLadder(min: any, max: any, market_interval: any, ladderType: any): any {
            var oddsRange: any[] = [];
            var odds: any = parseFloat(min);
            oddsRange.push(odds);

            while (odds < max) {
                var interval: any = 0;

                if (ladderType == common.enums.PriceLadderType.Classic) {

                    var range = common.helpers.Utility.GetPriceLadderUPRange(odds);
                    if (range) {
                        interval = range.interval;
                    }
                }
                else if (ladderType == common.enums.PriceLadderType.Finest) {
                    if (odds >= 1.01 && odds <= 1000) {
                        interval = 0.01;
                    }
                }
                else if (ladderType == common.enums.PriceLadderType.Line_Range) {
                    interval = market_interval;
                }

                if (interval > 0) {
                    odds = math.round(math.add(odds, interval), 2);
                }
                oddsRange.push(odds);
            }
            return oddsRange;
        }

