        public static getTimeZone(): any {
            var offset = new Date().getTimezoneOffset(), o = Math.abs(offset);
            return (offset < 0 ? "+" : "-") + ("00" + Math.floor(o / 60)).slice(-2) + ":" + ("00" + (o % 60)).slice(-2);
        }

        public static wrapTD(item: any): any { return "<td>" + (item != undefined ? item : '') + "</td>"; }
        public static wrapTR(item: any): any { return "<tr>" + (item != undefined ? item : '') + "</tr>"; }
        public static wrapTHead(item: any): any { return "<thead>" + item + "</thead>"; }
        public static wrapTBody(item: any): any { return "<tbody>" + item + "</tbody>"; }
        public static wrapTable(item: any): any { return "<table>" + item + "</table>"; }

        public static groupByDate(data: any[], datefield: any): any {
            const groups = data.reduce((groups, game) => {
                const date = moment(game[datefield]).format('DD/MM/YYYY');
                if (!groups[date]) {
                    groups[date] = [];
                }
                groups[date].push(game);
                return groups;
            }, {});
            const groupArrays = Object.keys(groups).map((date: any) => {
                return {
                    date: date,
                    values: groups[date]
                }
            });
            return groupArrays;
        }

        public static groupByField(data: any[], field: any): any {
            const groups = data.reduce((groups, game) => {
                const f = game[field];
                if (!groups[f]) {
                    groups[f] = [];
                }
                groups[f].push(game);
                return groups;
            }, {});
            const groupArrays = Object.keys(groups).map((f: any) => {
                return {
                    key: f,
                    values: groups[f]
                }
            });
            return groupArrays;
        }

        public static isCPPermission(pname: any): boolean {
            var plist = [];
            plist.push('cp.downline.manage.fullaccess');
            plist.push('cp.downline.manage.viewonly');
            plist.push('cp.transfer.fullaccess');
            plist.push('cp.riskmanagement.fullaccess');
            plist.push('cp.reports.fullaccess');
            plist.push('cp.pt.onoff.fullaccess');
            plist.push('cp.statements.fullaccess');
            plist.push('cp.aggregateaccounts.fullaccess');

            return plist.indexOf(pname) > -1;
        }

        public static setSessionPrice(item: any): any {
            if (!item.backPrice || item.backPrice.length <= 0) {
                item.backPrice = [{ price: '', size: '', percentage: '' }];
            }
            if (!item.layPrice || item.layPrice.length <= 0) {
                item.layPrice = [{ price: '', size: '', percentage: '' }];
            }
            if (item.backPrice.length != item.layPrice.length) {
                if (item.backPrice.length < item.layPrice.length) {
                    item.backPrice.push({ price: '', size: '', percentage: '' });
                }
                else {
                    item.layPrice.push({ price: '', size: '', percentage: '' });
                }
            }
            return item;
        }

